GOLDEN_PASS_THRESHOLD = 0.82

def run_golden_eval(
    dataset: GoldenDataset,
    agent_fn,    # (system: str, user_input: str) -> str
    score_fn,    # (case, output: str) -> float
) -> dict:
    results = []
    for case in dataset.cases:
        output = agent_fn(case.system, case.user_input)
        score  = score_fn(case, output)
        results.append({"id": case.id, "score": score, "tags": case.tags})

    n = len(results)
    mean_score = sum(r["score"] for r in results) / n if n else 0.0
    ci_pass    = mean_score >= GOLDEN_PASS_THRESHOLD

    # Per-tag breakdown — identifies which categories regressed
    tag_scores: dict = {}
    for r in results:
        for tag in r["tags"]:
            tag_scores.setdefault(tag, []).append(r["score"])
    tag_means = {tag: sum(s)/len(s) for tag, s in tag_scores.items()}

    return {
        "dataset":    f"{dataset.name}@{dataset.version}",
        "mean_score": mean_score,
        "ci_pass":    ci_pass,
        "by_tag":     tag_means,
        "verdict":    "PASS" if ci_pass else f"FAIL ({mean_score:.2f} < {GOLDEN_PASS_THRESHOLD})",
    }
